        self._listeners[event].append((callback, False))
        return self # Allows chaining

    def off(self, event, callback):
        if event not in self._listeners:
            return False

        initial_count = len(self._listeners[event])
        # Filter out the specific callback instance to remove it
        new_listeners = [(c, o) for c, o in self._listeners[event] if c != callback]

        removed = initial_count > len(new_listeners)

        if not new_listeners:
             del self._listeners[event]
        else:
             self._listeners[event] = new_listeners

        return removed # Return the actual boolean outcome of whether removal occurred.

    def once(self, event, callback):
        # Treat 'once' listeners as non-existent initially in general list, but hook up a wrapper.
        if event not in self._listeners:
            self._listeners[event] = []

        wrapper_callback = self._once_handler(event, callback)
        self._listeners[event].append((wrapper_callback, True)) # Mark as one-time

    def _once_handler(self, event, original_callback):
        """Returns a wrapper that executes the original callback once and removes itself."""
        def wrapper(*args, **kwargs):
            try:
                original_callback(*args, **kwargs)
                # Attempt to clean up immediately after successful execution
                if event in self._listeners:
                    new_list = [(c, o) for c, o in self._listeners[event] if (c, o) != (wrapper, True)]
                    self._listeners[event] = new_list

                    if not self._listeners[event]:
                        del self._listeners[event]

            except Exception:
                # Reraise any exceptions to ensure test failure detection
                raise
        return wrapper

    def emit(self, event, *args, **kwargs):
        if event in self._listeners:
            # Iterate over a copy of the list to handle dynamic removal during iteration (e.g., by once handlers)
            callbacks = list(self._listeners[event])
            for callback, is_once in callbacks:
